            override fun upgrade(preferences: SharedPreferences) {
                preferences.edit { remove("scrolling_buttons") }
            }
        }

        /**
         * Migrates bindings from removed commands FLIP_OR_ANSWER_RECOMMENDED and
         * FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED to FLIP_OR_ANSWER_EASE3 and FLIP_OR_ANSWER_EASE4.
         */
        internal class UpgradeAnswerButtonBindings : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE3
                )
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(preferences: SharedPreferences, oldKey: String, targetCommand: ViewerCommand) {
                val oldBindings = preferences.getString(oldKey, null) ?: return
                if (oldBindings.isEmpty()) {
                    preferences.edit { remove(oldKey) }
                    return
                }

                // Parse old bindings and add them to the target command
                val bindings = MappableBinding.fromPreferenceString(oldBindings)
                for (binding in bindings) {
                    targetCommand.addBindingAtEnd(preferences, binding)
                }

                // Remove the old key
                preferences.edit { remove(oldKey) }
            }
        }
    }
}"}

